import{_ as i,c as l,o as r,ah as t,ai as e}from"./chunks/framework.Cnj7lwEt.js";const u=JSON.parse('{"title":"91GIT - Китайская станция GitHub","description":"","frontmatter":{},"headers":[],"relativePath":"ru/91git.md","filePath":"ru/91git.md"}'),n={name:"ru/91git.md"};function s(o,a,h,d,c,_){return r(),l("div",null,a[0]||(a[0]=[t('<h1 id="_91git-китаиская-станция-github" tabindex="-1">91GIT - Китайская станция GitHub <a class="header-anchor" href="#_91git-китаиская-станция-github" aria-label="Permalink to “91GIT - Китайская станция GitHub”">​</a></h1><p><strong>URL доступа:</strong> <a href="https://91git.com/" target="_blank" rel="noreferrer">https://91git.com/</a></p><h2 id="_01-1-обзор-проекта" tabindex="-1">01.1- Обзор проекта <a class="header-anchor" href="#_01-1-обзор-проекта" aria-label="Permalink to “01.1- Обзор проекта”">​</a></h2><p>Китайская станция GitHub —— ищите репозитории GitHub одним щелчком, автоматически упаковывайте исходный код и ресурсы релиза, создавайте сжатые файлы для загрузки.</p><p>Специально разработана для локальной сетевой среды, помогает разработчикам быстро получать доступ к ресурсам проектов GitHub.</p><p><img src="'+e+'" alt="alt text"></p><h2 id="_01-2-особенности" tabindex="-1">01.2- Особенности <a class="header-anchor" href="#_01-2-особенности" aria-label="Permalink to “01.2- Особенности”">​</a></h2><ul><li>🔍 <strong>Поиск по ключевым словам</strong> - ищите репозитории GitHub по ключевым словам, сортируйте по количеству звезд</li><li>📥 <strong>Упаковка одним щелчком</strong> - автоматическая загрузка исходного кода + ресурсов релиза, создание двойного зашифрованного сжатого файла</li><li>🔥 <strong>Популярное на GitHub</strong> - отображение топ-10 новых репозиториев с высоким рейтингом, созданных на этой неделе</li><li>📊 <strong>Популярное на сайте</strong> - отображение репозиториев с наибольшим количеством упаковок за день/месяц</li><li>⏱️ <strong>Автоочистка</strong> - файлы пакетов автоматически удаляются через 3 минуты, если не загружены, экономия места на сервере</li></ul><h2 id="_01-3-технологическии-стек" tabindex="-1">01.3- Технологический стек <a class="header-anchor" href="#_01-3-технологическии-стек" aria-label="Permalink to “01.3- Технологический стек”">​</a></h2><ul><li><strong>Фронтенд</strong>: React + TypeScript + Vite + Tailwind CSS</li><li><strong>Анимация</strong>: Framer Motion</li><li><strong>Бэкенд</strong>: Node.js + Express</li><li><strong>Упаковка</strong>: archiver (ZIP)</li><li><strong>Шифрование</strong>: AES-256 + пароль ZIP</li></ul><h2 id="_01-4-сценарии-использования" tabindex="-1">01.4- Сценарии использования <a class="header-anchor" href="#_01-4-сценарии-использования" aria-label="Permalink to “01.4- Сценарии использования”">​</a></h2><h3 id="для-разработчиков" tabindex="-1">Для разработчиков <a class="header-anchor" href="#для-разработчиков" aria-label="Permalink to “Для разработчиков”">​</a></h3><ul><li>Быстрое получение исходного кода проектов GitHub</li><li>Загрузка полных ресурсов релиза</li><li>Упаковка ресурсов проекта для совместного использования</li></ul><h3 id="для-исследователеи" tabindex="-1">Для исследователей <a class="header-anchor" href="#для-исследователеи" aria-label="Permalink to “Для исследователей”">​</a></h3><ul><li>Пакетная загрузка исследовательских инструментов</li><li>Архивирование проектов с открытым исходным кодом</li><li>Создание локальной библиотеки ресурсов</li></ul><h3 id="для-корпоративных-пользователеи" tabindex="-1">Для корпоративных пользователей <a class="header-anchor" href="#для-корпоративных-пользователеи" aria-label="Permalink to “Для корпоративных пользователей”">​</a></h3><ul><li>Внутренний обмен инструментами разработки</li><li>Синхронизация ресурсов команды</li><li>Развертывание в офлайн-средах</li></ul><h2 id="_01-5-безопасность" tabindex="-1">01.5- Безопасность <a class="header-anchor" href="#_01-5-безопасность" aria-label="Permalink to “01.5- Безопасность”">​</a></h2><ul><li>✅ Двойное шифрование защиты</li><li>✅ Автоматическая очистка файлов</li><li>✅ Нет сбора данных пользователей</li><li>✅ Безопасный протокол передачи</li></ul><h2 id="_01-6-примечания" tabindex="-1">01.6- Примечания <a class="header-anchor" href="#_01-6-примечания" aria-label="Permalink to “01.6- Примечания”">​</a></h2><p>Если у вас есть вопросы или предложения, пожалуйста, свяжитесь с нами через:</p><ul><li>GitHub Issues</li><li>Электронная почта</li><li>Онлайн-поддержка</li></ul><hr><p><strong>Отказ от ответственности</strong>: Пожалуйста, используйте этот инструмент только для целей обучения и исследования. Соблюдайте условия использования GitHub и соответствующие правила.</p>',24)]))}const b=i(n,[["render",s]]);export{u as __pageData,b as default};
